def caesar_cipher(plaintext,shift):
    ciphertext = ""
    for char in plaintext: 
        if char == ' ':
            ciphertext += char
        elif  char.isupper():
            ciphertext += chr((ord(char) + shift - 65) % 26 + 65)
        else:
            ciphertext += chr((ord(char) + shift - 97) % 26 + 97)
    return ciphertext

