def valid(bo, num, pos):
    # Check row
    for i in range(len(bo[0])):
        if bo[pos[0]][i] == num and pos[1] != i:
            return False

    # Check column
    for i in range(len(bo)):
        if bo[i][pos[1]] == num and pos[0] != i:
            return False

    # Check box
    box_x = pos[1] // 3
    box_y = pos[0] // 3

    for i in range(box_y*3, box_y*3 + 3):
        for j in range(box_x * 3, box_x*3 + 3):
            if bo[i][j] == num and (i,j) != pos:
                return False

return True

def num2words(number): 
    ones = ["", "one ","two ", "three ", "four ", 
            "five ", "six ", "seven ", "eight ", 
            "nine ", "ten ", "eleven ", "twelve ", 
            "thirteen ", "fourteen ", "fifteen ", 
            "sixteen ", "seventeen ", "eighteen ", 
            "nineteen "] 
    tens = ["", "", "twenty ", "thirty ", "forty ", 
            "fifty ", "sixty ", "seventy ", "eighty ", 
            "ninety "] 
    if(number == 0): 
        return "zero"
    if(number < 0): 
        return "minus " + num2words(-1 * number) 
    if((number/1000) > 0): 
        return num2words(number/1000) + "thousand " + num2words(number%1000) 
    if((number / 100) > 0): 
        return num2words(number/100) + "hundred " + num2words(number%100) 
    if((number/10) > 1):
        return tens[int(number//10)] + num2words(number % 10) 
    else:
        return ones[int(number)]

