import heapq

class PriorityQueue:
    def __init__(self):
        self.heap = []
        self.count = 0

    def push(self, item, priority):
        entry = (priority, self.count, item)
        heapq.heappush(self.heap, entry)
        self.count += 1

    def pop(self):
        (_, _, item) = heapq.heappop(self.heap)
        return item

    def is_empty(self):
        return len(self.heap) == 0

def tsp(graph): 

    # Set initial values: 
    best_path = [] 
    best_path_cost = float('Inf') 

    # Iterate through all the possible paths: 
    for i in range(1 << len(graph[0])): 

        # Generate the binary string: 
        path = [] 
        for j in range(len(graph[0])): 
            if (i & (1 << j)) > 0: 
                path.append(j) 

        # Calculate the cost of the path: 
        cost = 0
        k = 0
        for j in range(len(path)): 
            if j+1 < len(path): 
                cost += graph[path[j]][path[j+1]] 
            else: 
                cost += graph[path[j]][path[0]] 

        # Check if the cost of the path is less than the 
        # current best path cost: 
        if cost < best_path_cost: 
            best_path_cost = cost 
            best_path = path 

    return best_path, best_path_cost

def commonPrefix(array):
    result = ""
    if len(array) > 0:
        # Find the minimum length of the word in the array.
        min_length = min([len(i) for i in array])

        # Iterate through the letters in the word with the minimum length.
        for i in range(min_length):
            curr_char = array[0][i]
            flag = True

            # For each letter, check if each of the words have that letter.
            for j in range(len(array)):
                if array[j][i] != curr_char:
                    flag = False
                    break
            if flag:
                result += curr_char
            else:
                break
    return result

