def classify_email(email):
    email_words = re.findall("[a-zA-Z0-9]+", email)
    frequency = nltk.FreqDist(email_words)
    common_words = frequency.most_common(30)

    spam_words = ["buy", "free", "unlimited", "cash", "click", "amazing"]
    is_spam = False

    for word in common_words:
        if word in spam_words:
            is_spam = True

    if is_spam:
        print("This email is classified as SPAM.")
    else:
        print("This email is classified as NOT SPAM.")

def get_longest_palindrome_substrings(s):
    n = len(s)
    dp = [[ False for _ in range(n)] for _ in range(n)]

    start, maxLen = 0, 0
    for i in range(n):
        dp[i][i] = True
    for i in range(n-1):
        j = i + 1
        if s[i] == s[j]:
            dp[i][j] = True
            start = i
            maxLen = 2

    for k in range(3, n+1):
        for i in range(n-k+1):
            j = i + k - 1
            if dp[i+1][j-1] and s[i] == s[j]:
                dp[i][j] = True

                if k > maxLen:
                    maxLen = k
                    start = i
    return s[start : start+maxLen]

