def createTree(tuples): 
    nodes = {} 
    for x, y in tuples: 

        # If x is not already a key 
        if x not in nodes: 
            # Create a new TreeNode 
            nodes[x] = TreeNode(x) 

        # If y is not already a key 
        if y not in nodes: 
            # Create a new TreeNode 
            nodes[y] = TreeNode(y) 

        # Append the new TreeNode to the children 
        # of the node X 
        nodes[x].add_child(nodes[y]) 

    # Return the root of the tree 
    return nodes['a']

